17	/// A slot in a queue.
18	struct Slot<T> {
19	    /// The current stamp.
20	    ///
21	    /// If the stamp equals the tail, this node will be next written to. If it equals head + 1,
22	    /// this node will be next read from.
23	    stamp: AtomicUsize,
24	
25	    /// The value in this slot.
26	    value: UnsafeCell<MaybeUninit<T>>,
27	}
28	
29	/// A bounded multi-producer multi-consumer queue.
30	///
31	/// This queue allocates a fixed-capacity buffer on construction, which is used to store pushed
32	/// elements. The queue cannot hold more elements than the buffer allows. Attempting to push an
33	/// element into a full queue will fail. Alternatively, [`force_push`] makes it possible for
34	/// this queue to be used as a ring-buffer. Having a buffer allocated upfront makes this queue
35	/// a bit faster than [`SegQueue`].
36	///
37	/// [`force_push`]: ArrayQueue::force_push
38	/// [`SegQueue`]: super::SegQueue
39	///
40	/// # Examples
41	///
42	/// ```
43	/// use crossbeam_queue::ArrayQueue;
44	///
45	/// let q = ArrayQueue::new(2);
46	///
47	/// assert_eq!(q.push('a'), Ok(()));
48	/// assert_eq!(q.push('b'), Ok(()));
49	/// assert_eq!(q.push('c'), Err('c'));
50	/// assert_eq!(q.pop(), Some('a'));
51	/// ```
52	pub struct ArrayQueue<T> {
53	    /// The head of the queue.
54	    ///
55	    /// This value is a "stamp" consisting of an index into the buffer and a lap, but packed into a
56	    /// single `usize`. The lower bits represent the index, while the upper bits represent the lap.
57	    ///
58	    /// Elements are popped from the head of the queue.
59	    head: CachePadded<AtomicUsize>,
60	
61	    /// The tail of the queue.
62	    ///
63	    /// This value is a "stamp" consisting of an index into the buffer and a lap, but packed into a
64	    /// single `usize`. The lower bits represent the index, while the upper bits represent the lap.
65	    ///
66	    /// Elements are pushed into the tail of the queue.
67	    tail: CachePadded<AtomicUsize>,
68	
69	    /// The buffer holding slots.
70	    buffer: Box<[Slot<T>]>,
71	
72	    /// A stamp with the value of `{ lap: 1, index: 0 }`.
73	    one_lap: usize,
74	}
75	
76	unsafe impl<T: Send> Sync for ArrayQueue<T> {}
77	unsafe impl<T: Send> Send for ArrayQueue<T> {}
