429	    /// Returns the capacity of the queue.
430	    ///
431	    /// # Examples
432	    ///
433	    /// ```
434	    /// use crossbeam_queue::ArrayQueue;
435	    ///
436	    /// let q = ArrayQueue::<i32>::new(100);
437	    ///
438	    /// assert_eq!(q.capacity(), 100);
439	    /// ```
440	    #[inline]
441	    pub fn capacity(&self) -> usize {
442	        self.buffer.len()
443	    }
444	
445	    /// Returns `true` if the queue is empty.
446	    ///
447	    /// # Examples
448	    ///
449	    /// ```
450	    /// use crossbeam_queue::ArrayQueue;
451	    ///
452	    /// let q = ArrayQueue::new(100);
453	    ///
454	    /// assert!(q.is_empty());
455	    /// q.push(1).unwrap();
456	    /// assert!(!q.is_empty());
457	    /// ```
458	    pub fn is_empty(&self) -> bool {
459	        let head = self.head.load(Ordering::SeqCst);
460	        let tail = self.tail.load(Ordering::SeqCst);
461	
462	        // Is the tail lagging one lap behind head?
463	        // Is the tail equal to the head?
464	        //
465	        // Note: If the head changes just before we load the tail, that means there was a moment
466	        // when the channel was not empty, so it is safe to just return `false`.
467	        tail == head
468	    }
469	
470	    /// Returns `true` if the queue is full.
471	    ///
472	    /// # Examples
473	    ///
474	    /// ```
475	    /// use crossbeam_queue::ArrayQueue;
476	    ///
477	    /// let q = ArrayQueue::new(1);
478	    ///
479	    /// assert!(!q.is_full());
480	    /// q.push(1).unwrap();
481	    /// assert!(q.is_full());
482	    /// ```
483	    pub fn is_full(&self) -> bool {
484	        let tail = self.tail.load(Ordering::SeqCst);
485	        let head = self.head.load(Ordering::SeqCst);
486	
487	        // Is the head lagging one lap behind tail?
488	        //
489	        // Note: If the tail changes just before we load the head, that means there was a moment
490	        // when the queue was not full, so it is safe to just return `false`.
491	        head.wrapping_add(self.one_lap) == tail
492	    }
