494	    /// Returns the number of elements in the queue.
495	    ///
496	    /// # Examples
497	    ///
498	    /// ```
499	    /// use crossbeam_queue::ArrayQueue;
500	    ///
501	    /// let q = ArrayQueue::new(100);
502	    /// assert_eq!(q.len(), 0);
503	    ///
504	    /// q.push(10).unwrap();
505	    /// assert_eq!(q.len(), 1);
506	    ///
507	    /// q.push(20).unwrap();
508	    /// assert_eq!(q.len(), 2);
509	    /// ```
510	    pub fn len(&self) -> usize {
511	        loop {
512	            // Load the tail, then load the head.
513	            let tail = self.tail.load(Ordering::SeqCst);
514	            let head = self.head.load(Ordering::SeqCst);
515	
516	            // If the tail didn't change, we've got consistent values to work with.
517	            if self.tail.load(Ordering::SeqCst) == tail {
518	                let hix = head & (self.one_lap - 1);
519	                let tix = tail & (self.one_lap - 1);
520	
521	                return if hix < tix {
522	                    tix - hix
523	                } else if hix > tix {
524	                    self.capacity() - hix + tix
525	                } else if tail == head {
526	                    0
527	                } else {
528	                    self.capacity()
529	                };
530	            }
531	        }
532	    }
533	}
