535	impl<T> Drop for ArrayQueue<T> {
536	    fn drop(&mut self) {
537	        if mem::needs_drop::<T>() {
538	            // Get the index of the head.
539	            let head = *self.head.get_mut();
540	            let tail = *self.tail.get_mut();
541	
542	            let hix = head & (self.one_lap - 1);
543	            let tix = tail & (self.one_lap - 1);
544	
545	            let len = if hix < tix {
546	                tix - hix
547	            } else if hix > tix {
548	                self.capacity() - hix + tix
549	            } else if tail == head {
550	                0
551	            } else {
552	                self.capacity()
553	            };
554	
555	            // Loop over all slots that hold a message and drop them.
556	            for i in 0..len {
557	                // Compute the index of the next slot holding a message.
558	                let index = if hix + i < self.capacity() {
559	                    hix + i
560	                } else {
561	                    hix + i - self.capacity()
562	                };
563	
564	                unsafe {
565	                    debug_assert!(index < self.buffer.len());
566	                    let slot = self.buffer.get_unchecked_mut(index);
567	                    (*slot.value.get()).assume_init_drop();
568	                }
569	            }
570	        }
571	    }
572	}
