598	    fn next(&mut self) -> Option<Self::Item> {
599	        let value = &mut self.value;
600	        let head = *value.head.get_mut();
601	        if value.head.get_mut() != value.tail.get_mut() {
602	            let index = head & (value.one_lap - 1);
603	            let lap = head & !(value.one_lap - 1);
604	            // SAFETY: We have mutable access to this, so we can read without
605	            // worrying about concurrency. Furthermore, we know this is
606	            // initialized because it is the value pointed at by `value.head`
607	            // and this is a non-empty queue.
608	            let val = unsafe {
609	                debug_assert!(index < value.buffer.len());
610	                let slot = value.buffer.get_unchecked_mut(index);
611	                slot.value.get().read().assume_init()
612	            };
613	            let new = if index + 1 < value.capacity() {
614	                // Same lap, incremented index.
615	                // Set to `{ lap: lap, index: index + 1 }`.
616	                head + 1
617	            } else {
618	                // One lap forward, index wraps around to zero.
619	                // Set to `{ lap: lap.wrapping_add(1), index: 0 }`.
620	                lap.wrapping_add(value.one_lap)
621	            };
622	            *value.head.get_mut() = new;
623	            Some(val)
624	        } else {
625	            None
626	        }
627	    }
628	}
