585	impl<T> Stealer<T> {
586	    /// Returns `true` if the queue is empty.
587	    ///
588	    /// ```
589	    /// use crossbeam_deque::Worker;
590	    ///
591	    /// let w = Worker::new_lifo();
592	    /// let s = w.stealer();
593	    ///
594	    /// assert!(s.is_empty());
595	    /// w.push(1);
596	    /// assert!(!s.is_empty());
597	    /// ```
598	    pub fn is_empty(&self) -> bool {
599	        let f = self.inner.front.load(Ordering::Acquire);
600	        atomic::fence(Ordering::SeqCst);
601	        let b = self.inner.back.load(Ordering::Acquire);
602	        b.wrapping_sub(f) <= 0
603	    }
604	
605	    /// Returns the number of tasks in the deque.
606	    ///
607	    /// ```
608	    /// use crossbeam_deque::Worker;
609	    ///
610	    /// let w = Worker::new_lifo();
611	    /// let s = w.stealer();
612	    ///
613	    /// assert_eq!(s.len(), 0);
614	    /// w.push(1);
615	    /// assert_eq!(s.len(), 1);
616	    /// w.push(2);
617	    /// assert_eq!(s.len(), 2);
618	    /// ```
619	    pub fn len(&self) -> usize {
620	        let f = self.inner.front.load(Ordering::Acquire);
621	        atomic::fence(Ordering::SeqCst);
622	        let b = self.inner.back.load(Ordering::Acquire);
623	        b.wrapping_sub(f).max(0) as usize
624	    }
625	
626	    /// Steals a task from the queue.
627	    ///
628	    /// # Examples
629	    ///
630	    /// ```
631	    /// use crossbeam_deque::{Steal, Worker};
632	    ///
633	    /// let w = Worker::new_lifo();
634	    /// w.push(1);
635	    /// w.push(2);
636	    ///
637	    /// let s = w.stealer();
638	    /// assert_eq!(s.steal(), Steal::Success(1));
639	    /// assert_eq!(s.steal(), Steal::Success(2));
640	    /// ```
641	    pub fn steal(&self) -> Steal<T> {
642	        // Load the front index.
643	        let f = self.inner.front.load(Ordering::Acquire);
644	
645	        // A SeqCst fence is needed here.
