1921	            // ThreadSanitizer does not understand fences, so we omit fence and do store with Release ordering.
1922	            #[cfg(not(crossbeam_sanitize_thread))]
1923	            atomic::fence(Ordering::Release);
1924	            let store_order = if cfg!(crossbeam_sanitize_thread) {
1925	                Ordering::Release
1926	            } else {
1927	                Ordering::Relaxed
1928	            };
1929	
1930	            // Update the back index in the destination queue.
1931	            dest.inner
1932	                .back
1933	                .store(dest_b.wrapping_add(batch_size as isize), store_order);
1934	
1935	            // Destroy the block if we've reached the end, or if another thread wanted to destroy
1936	            // but couldn't because we were busy reading from the slot.
1937	            if new_offset == BLOCK_CAP {
1938	                Block::destroy(block, offset);
1939	            } else {
1940	                for i in offset..new_offset {
1941	                    let slot = (*block).slots.get_unchecked(i);
1942	
1943	                    if slot.state.fetch_or(READ, Ordering::AcqRel) & DESTROY != 0 {
1944	                        Block::destroy(block, offset);
1945	                        break;
1946	                    }
1947	                }
1948	            }
1949	
1950	            Steal::Success(task.assume_init())
