1973	    /// Returns the number of tasks in the queue.
1974	    ///
1975	    /// # Examples
1976	    ///
1977	    /// ```
1978	    /// use crossbeam_deque::Injector;
1979	    ///
1980	    /// let q = Injector::new();
1981	    ///
1982	    /// assert_eq!(q.len(), 0);
1983	    /// q.push(1);
1984	    /// assert_eq!(q.len(), 1);
1985	    /// q.push(1);
1986	    /// assert_eq!(q.len(), 2);
1987	    /// ```
1988	    pub fn len(&self) -> usize {
1989	        loop {
1990	            // Load the tail index, then load the head index.
1991	            let mut tail = self.tail.index.load(Ordering::SeqCst);
1992	            let mut head = self.head.index.load(Ordering::SeqCst);
1993	
1994	            // If the tail index didn't change, we've got consistent indices to work with.
1995	            if self.tail.index.load(Ordering::SeqCst) == tail {
1996	                // Erase the lower bits.
1997	                tail &= !((1 << SHIFT) - 1);
1998	                head &= !((1 << SHIFT) - 1);
1999	
2000	                // Fix up indices if they fall onto block ends.
2001	                if (tail >> SHIFT) & (LAP - 1) == LAP - 1 {
2002	                    tail = tail.wrapping_add(1 << SHIFT);
2003	                }
2004	                if (head >> SHIFT) & (LAP - 1) == LAP - 1 {
2005	                    head = head.wrapping_add(1 << SHIFT);
2006	                }
2007	
2008	                // Rotate indices so that head falls into the first block.
2009	                let lap = (head >> SHIFT) / LAP;
2010	                tail = tail.wrapping_sub((lap * LAP) << SHIFT);
2011	                head = head.wrapping_sub((lap * LAP) << SHIFT);
2012	
2013	                // Remove the lower bits.
2014	                tail >>= SHIFT;
2015	                head >>= SHIFT;
2016	
2017	                // Return the difference minus the number of blocks between tail and head.
2018	                return tail - head - tail / LAP;
2019	            }
2020	        }
2021	    }
2022	}
