2065	/// Possible outcomes of a steal operation.
2066	///
2067	/// # Examples
2068	///
2069	/// There are lots of ways to chain results of steal operations together:
2070	///
2071	/// ```
2072	/// use crossbeam_deque::Steal::{self, Empty, Retry, Success};
2073	///
2074	/// let collect = |v: Vec<Steal<i32>>| v.into_iter().collect::<Steal<i32>>();
2075	///
2076	/// assert_eq!(collect(vec![Empty, Empty, Empty]), Empty);
2077	/// assert_eq!(collect(vec![Empty, Retry, Empty]), Retry);
2078	/// assert_eq!(collect(vec![Retry, Success(1), Empty]), Success(1));
2079	///
2080	/// assert_eq!(collect(vec![Empty, Empty]).or_else(|| Retry), Retry);
2081	/// assert_eq!(collect(vec![Retry, Empty]).or_else(|| Success(1)), Success(1));
