2083	#[must_use]
2084	#[derive(PartialEq, Eq, Copy, Clone)]
2085	pub enum Steal<T> {
2086	    /// The queue was empty at the time of stealing.
2087	    Empty,
2088	
2089	    /// At least one task was successfully stolen.
2090	    Success(T),
2091	
2092	    /// The steal operation needs to be retried.
2093	    Retry,
2094	}
