2213	impl<T> FromIterator<Self> for Steal<T> {
2214	    /// Consumes items until a `Success` is found and returns it.
2215	    ///
2216	    /// If no `Success` was found, but there was at least one `Retry`, then returns `Retry`.
2217	    /// Otherwise, `Empty` is returned.
2218	    fn from_iter<I>(iter: I) -> Self
2219	    where
2220	        I: IntoIterator<Item = Self>,
2221	    {
2222	        let mut retry = false;
